INSERT INTO housing_listings (id, user_id, title, description, listing_type, price_monthly, bedrooms, bathrooms, address, city, latitude, longitude, available_from, furnished, utilities, pets_allowed, gender_pref, student_only, amenities, languages, is_active) VALUES
(gen_random_uuid(), NULL, 'Furnished Room near uOttawa Campus', 'Bright private room in a 3-bedroom apartment, 5-minute walk to uOttawa campus. Shared kitchen and bathroom. Quiet neighbourhood. Laundry in building. Internet included.', 'room', 750, 1, 1, '275 Laurier Ave E', 'Ottawa', 45.4231, -75.6831, '2026-05-01', true, true, false, NULL, true, '{wifi,laundry,heating,air_conditioning}', '{en,ar}', true),
(gen_random_uuid(), NULL, 'Modern 1-Bedroom Apartment - Sandy Hill', 'Spacious one-bedroom apartment in Sandy Hill, steps from uOttawa. Recently renovated with in-suite laundry, dishwasher and balcony. Secure entry building.', 'apartment', 1650, 1, 1, '180 Osgoode St', 'Ottawa', 45.4245, -75.6780, '2026-06-01', false, false, false, NULL, false, '{laundry,dishwasher,balcony,parking}', '{en,fr}', true),
(gen_random_uuid(), NULL, 'Affordable Basement Suite near Carleton', 'Clean basement apartment with separate entrance near Carleton campus. Includes bedroom, living area, kitchenette and full bathroom. Bus stop steps away.', 'basement', 900, 1, 1, '1580 Prince of Wales Dr', 'Ottawa', 45.3812, -75.6970, '2026-05-01', true, true, false, NULL, true, '{wifi,heating,separate_entrance}', '{en}', true),
(gen_random_uuid(), NULL, 'Homestay with Canadian Family - Barrhaven', 'Welcoming Canadian family offering homestay for international students. Private room with meals included (breakfast and dinner). Practice English in a home environment.', 'homestay', 1100, 1, 1, '89 Berrigan Dr', 'Ottawa', 45.3260, -75.7360, '2026-04-15', true, true, false, NULL, true, '{wifi,meals_included,heating,parking}', '{en}', true),
(gen_random_uuid(), NULL, 'Shared 2-Bedroom Apartment - Centretown', 'Looking for a roommate to share a 2-bedroom apartment in Centretown. Walking distance to Parliament, Rideau Centre and both universities. Great nightlife nearby.', 'room', 825, 1, 1, '440 Kent St', 'Ottawa', 45.4166, -75.7003, '2026-05-15', false, true, false, NULL, false, '{wifi,laundry,gym,heating}', '{en,zh}', true),
(gen_random_uuid(), NULL, 'Large 2-Bedroom Apartment - Heron Gate', 'Spacious two-bedroom apartment in diverse Heron Gate neighbourhood. Close to bus routes, Billings Bridge Mall and grocery stores. Great for families or roommates.', 'apartment', 1450, 2, 1, '1455 Heron Rd', 'Ottawa', 45.3870, -75.6600, '2026-06-01', false, true, true, NULL, false, '{laundry,parking,balcony,storage}', '{en,ar,so}', true),
(gen_random_uuid(), NULL, 'Studio Apartment - Byward Market', 'Cozy studio in the heart of the Byward Market. Perfect for a single student. Walking distance to uOttawa, restaurants and shops. Heritage building with character.', 'apartment', 1350, 0, 1, '55 Clarence St', 'Ottawa', 45.4290, -75.6920, '2026-05-01', true, true, false, NULL, false, '{wifi,heating,air_conditioning}', '{en,fr}', true),
(gen_random_uuid(), NULL, 'Room in Townhouse near Algonquin College', 'Private room available in a 4-bedroom townhouse shared with other students. Common areas are clean and well-maintained. Close to Algonquin College and bus routes.', 'room', 600, 1, 1, '1245 Baseline Rd', 'Ottawa', 45.3520, -75.7560, '2026-04-01', true, true, false, NULL, true, '{wifi,laundry,heating,parking}', '{en,hi}', true);

