INSERT INTO forum_posts (id, user_id, title, content, category, tags, city, upvotes, reply_count, pinned, language) VALUES
(gen_random_uuid(), NULL, 'How do I get my SIN number in Ottawa?', 'I just arrived in Ottawa as an international student. I need a Social Insurance Number to start working on campus. Can anyone explain the process? Do I need to go in person or can I apply online? What documents should I bring? Thanks in advance!', 'immigration', '{sin,documents,work_permit,newcomer}', 'Ottawa', 24, 0, false, 'en'),
(gen_random_uuid(), NULL, 'Best bank accounts for international students?', 'Hi everyone, I am trying to choose a bank for my first Canadian account. I have heard that some banks offer free accounts for newcomers. Which bank has the best deal for international students? I care about no monthly fees, a good app and being able to send money home easily.', 'banking', '{banking,student_account,newcomer,money_transfer}', 'Ottawa', 31, 0, false, 'en'),
(gen_random_uuid(), NULL, 'Looking for halal food in Ottawa', 'Salam everyone! I just moved to Ottawa for school and I am looking for good halal restaurants and grocery stores. Anywhere near uOttawa or downtown would be great. Also, are there any halal meal prep services? Would love your recommendations!', 'community', '{halal,food,restaurants,groceries,muslim}', 'Ottawa', 18, 0, false, 'en'),
(gen_random_uuid(), NULL, 'How to prepare for Canadian winter?', 'This will be my first winter in Canada and I am from a tropical country. I have no idea what to expect! What kind of clothes do I need? How cold does it actually get in Ottawa? Any tips for surviving the winter months? I heard it can go below -30C which sounds terrifying.', 'general', '{winter,clothing,weather,tips,newcomer}', 'Ottawa', 42, 0, false, 'en'),
(gen_random_uuid(), NULL, 'Part-time job tips while studying?', 'I am an international student allowed to work 20 hours per week off campus. What are the best part-time jobs for students in Ottawa? I have experience in retail but I am open to anything. How do I balance work and a full course load? Any advice appreciated.', 'jobs', '{part_time,work_permit,student_jobs,employment}', 'Ottawa', 27, 0, false, 'en');

