-- KNOWLEDGE BASE (20 rows) — embeddings set to NULL
-- ============================================================

INSERT INTO knowledge_base (id, title, content, source_url, source_name, category, province, status_type, language, embedding) VALUES
(gen_random_uuid(), 'How to Apply for a Social Insurance Number (SIN)',
'A Social Insurance Number (SIN) is required to work in Canada or access government programs. International students can apply in person at a Service Canada office. Required documents: valid passport, study permit, and a letter of acceptance from your designated learning institution (DLI). Processing is usually immediate if you visit in person. You can also apply by mail. Your SIN starting with 9 is temporary and tied to your work authorization. In Ottawa, the nearest Service Canada office is at 110 Laurier Ave W.',
'https://www.canada.ca/en/employment-social-development/services/sin/apply.html', 'Government of Canada', 'immigration', 'Ontario', '{international_student,permanent_resident,refugee}', 'en', NULL),

(gen_random_uuid(), 'OHIP Enrollment and 3-Month Waiting Period',
'Ontario Health Insurance Plan (OHIP) covers most medical services for eligible residents. New permanent residents and refugees must complete a 3-month waiting period before coverage begins. During this waiting period, you should obtain private health insurance (such as UHIP for university students). To apply, visit a ServiceOntario office with proof of identity, Ontario residency and immigration status. International students on study permits are generally NOT eligible for OHIP and must use UHIP or equivalent university insurance.',
'https://www.ontario.ca/page/apply-ohip-and-get-health-card', 'Government of Ontario', 'health', 'Ontario', '{permanent_resident,refugee}', 'en', NULL),

(gen_random_uuid(), 'Study Permit Work Rules: 20 Hours Per Week',
'International students with a valid study permit can work up to 20 hours per week during regular academic sessions and full-time during scheduled breaks (such as winter and summer holidays). You must be enrolled full-time at a designated learning institution (DLI) and have a valid study permit that says you are allowed to work off campus. No separate work permit is needed. On-campus work has no hour limit. Violating the 20-hour rule can result in loss of student status and deportation.',
'https://www.canada.ca/en/immigration-refugees-citizenship/services/study-canada/work.html', 'IRCC', 'employment', NULL, '{international_student}', 'en', NULL),

(gen_random_uuid(), 'Filing Taxes as a Newcomer in Canada',
'All residents of Canada, including international students and newcomers, may need to file a tax return. Even if you earned no income, filing a return can qualify you for benefits like the GST/HST credit and Canada Child Benefit. The tax year runs January to December and returns are due by April 30. Use a free tax clinic (such as those offered by community organizations through the CVITP program) or free software like Wealthsimple Tax. You will need your SIN and any T4 slips from employers.',
'https://www.canada.ca/en/revenue-agency/services/tax/individuals/topics/about-your-tax-return/tax-return/completing-a-tax-return/personal-income/newcomers-canada-immigrants.html', 'Canada Revenue Agency', 'immigration', NULL, '{international_student,permanent_resident,refugee}', 'en', NULL),

(gen_random_uuid(), 'GST/HST Credit for Newcomers',
'The GST/HST credit is a tax-free quarterly payment to help individuals and families with low or modest income offset the GST/HST they pay. Newcomers, including international students who file a tax return, may be eligible. To apply, file your income tax return and complete Form RC151 (GST/HST Credit Application for Individuals Who Become Residents of Canada). Payments are issued quarterly in January, April, July and October. For a single person, the maximum annual credit is approximately $496.',
'https://www.canada.ca/en/revenue-agency/services/child-family-benefits/gsthstc-eligibility.html', 'Canada Revenue Agency', 'banking', NULL, '{international_student,permanent_resident,refugee}', 'en', NULL),

(gen_random_uuid(), 'Post-Graduation Work Permit (PGWP) Eligibility',
'After graduating from a designated learning institution (DLI) in Canada, international students may apply for a Post-Graduation Work Permit (PGWP). The PGWP allows you to work for any employer in Canada. The length of the permit depends on your program length: programs of 8 months to 2 years receive a PGWP equal to program length; programs of 2+ years receive a 3-year PGWP. You must apply within 180 days of receiving written confirmation of program completion. You must have maintained full-time student status.',
'https://www.canada.ca/en/immigration-refugees-citizenship/services/study-canada/work/after-graduation/eligibility.html', 'IRCC', 'immigration', NULL, '{international_student}', 'en', NULL),

(gen_random_uuid(), 'Getting an Ontario Driver''s Licence',
'New Ontario residents must get an Ontario driver''s licence within 60 days. Ontario uses a graduated licensing system (G1 -> G2 -> G). If you have a valid licence from certain countries (USA, UK, Australia, Japan, South Korea, etc.), you may exchange it directly without testing. Others must start with a G1 written test ($159.75 fee). The G1 test covers road signs and rules. After passing, you must wait 12 months (or 8 months with an approved driving course) before taking the G2 road test.',
'https://www.ontario.ca/page/get-drivers-licence', 'Government of Ontario', 'transport', 'Ontario', '{international_student,permanent_resident,refugee}', 'en', NULL),

(gen_random_uuid(), 'Opening a Bank Account as a Newcomer',
'You can open a bank account in Canada even before arriving. Major banks (TD, RBC, Scotiabank, BMO, CIBC) all offer newcomer packages with no monthly fees for the first year and credit cards requiring no Canadian credit history. To open an account you need: two pieces of ID (passport and study/work permit), proof of address (can be temporary), and your SIN (optional at account opening but needed for interest reporting). Most banks have branches near university campuses.',
'https://www.canada.ca/en/financial-consumer-agency/services/banking/opening-bank-account.html', 'Financial Consumer Agency of Canada', 'banking', NULL, '{international_student,permanent_resident,refugee}', 'en', NULL),

(gen_random_uuid(), 'Healthcare Without OHIP: Options for International Students',
'International students in Ontario are not eligible for OHIP and must have private health insurance. Ontario universities require enrollment in the University Health Insurance Plan (UHIP) which costs approximately $756 per year. UHIP covers doctor visits, hospital stays, emergency care, mental health services and prescription drugs. For additional coverage (dental, vision, extended prescriptions), check your student union supplementary insurance plan. Walk-in clinics accept UHIP but always carry your UHIP card.',
'https://uhip.ca/Enrollment/Coverage', 'UHIP', 'health', 'Ontario', '{international_student}', 'en', NULL),

(gen_random_uuid(), 'Express Entry: Overview for Skilled Workers',
'Express Entry is Canada''s main pathway for skilled workers to become permanent residents. It manages three immigration programs: Federal Skilled Worker, Federal Skilled Trades, and Canadian Experience Class. Candidates create an online profile and are ranked using the Comprehensive Ranking System (CRS). Top-ranked candidates receive Invitations to Apply (ITAs) in regular draws. Key factors: age, education, language scores (IELTS/CELPIP/TEF), work experience, and Canadian connections. Processing time is approximately 6 months.',
'https://www.canada.ca/en/immigration-refugees-citizenship/services/immigrate-canada/express-entry.html', 'IRCC', 'immigration', NULL, '{international_student,permanent_resident}', 'en', NULL),

(gen_random_uuid(), 'Renting in Ontario: Know Your Rights',
'The Residential Tenancies Act (RTA) protects tenants in Ontario. Key rights: landlords cannot increase rent more than the annual guideline (2.5% for 2024); landlords must provide 24 hours written notice before entering; security deposits beyond last month''s rent are illegal; landlords cannot refuse tenants based on immigration status. If you have a dispute, contact the Landlord and Tenant Board (LTB). Always get a written lease (Ontario has a standard lease form). Never pay cash without a receipt.',
'https://www.ontario.ca/page/renting-ontario-your-rights', 'Government of Ontario', 'housing', 'Ontario', '{international_student,permanent_resident,refugee}', 'en', NULL),

(gen_random_uuid(), 'Getting a Canadian Cell Phone Plan',
'Major carriers include Rogers, Bell and Telus with extensive coverage. For budget options, consider their sub-brands: Fido, Virgin Plus, Koodo and Public Mobile. Prepaid plans start around $25/month. You need a Canadian bank account or credit card for postpaid plans. Bring-your-own-device (BYOD) plans save money. Ensure your phone supports Canadian LTE bands. Port your number if switching carriers. Freedom Mobile and Videotron offer competitive plans in certain cities.',
NULL, 'MaplePath Knowledge', 'community', NULL, '{international_student,permanent_resident,refugee,visitor}', 'en', NULL),

(gen_random_uuid(), 'Navigating Ottawa by Public Transit',
'OC Transpo is Ottawa''s public transit system. University students get a U-Pass included in tuition providing unlimited travel. Use a Presto card for pay-per-ride ($3.70 per ride). The Confederation Line (O-Train Line 1) runs east-west through downtown connecting Tunney''s Pasture to Blair. The Trillium Line (Line 2) runs north-south. Google Maps and the OC Transpo app provide real-time trip planning. Night service (routes 90-99) runs on weekends.',
'https://www.octranspo.com', 'OC Transpo', 'transport', 'Ontario', '{international_student,permanent_resident,refugee,visitor}', 'en', NULL),

(gen_random_uuid(), 'Canadian Workplace Culture for Newcomers',
'Canadian workplaces tend to value punctuality, direct but polite communication, and teamwork. Arrive on time or a few minutes early. Address colleagues by first name unless told otherwise. Two weeks notice is standard when leaving a job. Minimum wage in Ontario is $16.55/hour. You are entitled to breaks, overtime pay and a safe workplace. If you face workplace discrimination or harassment, contact the Ontario Human Rights Commission or your university''s equity office.',
NULL, 'MaplePath Knowledge', 'employment', 'Ontario', '{international_student,permanent_resident,refugee}', 'en', NULL),

(gen_random_uuid(), 'Building Canadian Credit History',
'Building credit is essential for renting apartments, getting loans, and more. Start with a secured credit card from your bank or a student credit card. Use it for small purchases and pay the full balance every month. After 6 months of responsible use, your credit score will start building. Check your score free through Borrowell or Credit Karma. Avoid carrying a balance, making late payments, or applying for too many cards at once. A good credit score in Canada is 650 and above.',
NULL, 'MaplePath Knowledge', 'banking', NULL, '{international_student,permanent_resident,refugee}', 'en', NULL),

(gen_random_uuid(), 'Emergency Numbers and Services in Canada',
'Call 911 for police, fire or medical emergencies. For non-emergency police matters, call your local police non-emergency line (Ottawa: 613-236-1222). Telehealth Ontario (1-866-797-0000) provides 24/7 free health advice by phone. For mental health crises, call the Crisis Line at 1-833-456-4566 (24/7). For poison control, call 1-800-268-9017. In case of severe weather, check Environment Canada weather warnings. Keep your address memorized or written down in case of emergency.',
NULL, 'MaplePath Knowledge', 'health', 'Ontario', '{international_student,permanent_resident,refugee,visitor}', 'en', NULL),

(gen_random_uuid(), 'Winter Survival Guide for Newcomers',
'Ottawa winters are cold with temperatures dropping to -25C or below with wind chill. Essential gear: insulated winter jacket, thermal base layers, waterproof winter boots with good traction, warm hat covering ears, insulated gloves, and a scarf. Layer your clothing. Black ice is a major hazard on sidewalks. Keep an emergency kit in your car if driving. The heating bill increases in winter so budget accordingly. Indoor humidity drops significantly so consider a humidifier. Winter tires are strongly recommended.',
NULL, 'MaplePath Knowledge', 'community', 'Ontario', '{international_student,permanent_resident,refugee,visitor}', 'en', NULL),

(gen_random_uuid(), 'Canadian Phone and Internet Scams to Avoid',
'Common scams targeting newcomers: CRA scam calls threatening arrest for unpaid taxes (CRA never calls to threaten); immigration scam calls claiming your SIN is compromised; fake job offers asking for upfront fees; rental scams for apartments that do not exist. Never give personal information over unsolicited calls. The CRA will never ask for payment via gift cards or cryptocurrency. Report scams to the Canadian Anti-Fraud Centre at 1-888-495-8501. If unsure, hang up and call the organization directly.',
'https://www.antifraudcentre-centreantifraude.ca', 'Canadian Anti-Fraud Centre', 'community', NULL, '{international_student,permanent_resident,refugee,visitor}', 'en', NULL),

(gen_random_uuid(), 'Study Permit Extension Process',
'You should apply to extend your study permit at least 30 days before it expires (recommended 90 days ahead). Apply online through your IRCC account. Required: valid passport, letter of enrollment from DLI, proof of financial support, and digital photos. Processing time varies (typically 60-120 days). If you apply before your permit expires, you can stay in Canada on implied status until a decision is made. If your permit expires without extension, you may lose your student status and work authorization.',
'https://www.canada.ca/en/immigration-refugees-citizenship/services/study-canada/extend-study-permit.html', 'IRCC', 'immigration', NULL, '{international_student}', 'en', NULL),

(gen_random_uuid(), 'Free English and French Language Classes',
'LINC (Language Instruction for Newcomers to Canada) provides free English classes for permanent residents and refugees. Classes range from beginner (CLB 1) to advanced (CLB 8). Some programs include free childcare and transportation allowances. In Ottawa, LINC is offered at OCISO, Catholic Centre for Immigrants, and Algonquin College. For French, look for CLIC (Cours de Langue pour les Immigrants au Canada). International students can access ESL classes through their university or community colleges for a fee.',
'https://www.canada.ca/en/immigration-refugees-citizenship/services/new-immigrants/new-life-canada/improve-english-french/classes.html', 'IRCC', 'education', 'Ontario', '{permanent_resident,refugee}', 'en', NULL);

