(gen_random_uuid(), NULL, 'International Student Services - uOttawa', 'education', 'Support office for international students at uOttawa providing immigration advising, orientation and cultural programming.', '90 University Pvt, Jock Turcot Building', 45.4235, -75.6836, 'Ottawa', '{en,fr}', 'https://www.uottawa.ca/international/', '613-562-5847', 'Mon-Fri 9am-4:30pm', true, 13);
